// Inferência automática — prefira isso
const name = 'Helber';      // TypeScript sabe: string
const age = 30;             // TypeScript sabe: number
const active = true;        // TypeScript sabe: boolean

// Anotação explícita — use quando necessário
let result: string;
result = calcSomething();   // sem inferência possível antes da atribuição

// Tipos especiais
const nothing: null = null;
const undef: undefined = undefined;
const anything: unknown = fetchData(); // prefira unknown a any

// Arrays
const names: string[] = ['Ana', 'Bob'];
const ids: Array<number> = [1, 2, 3];

// Array de objetos
const users: Array<{ id: number; name: string }> = [];

// Tupla: posição 0 é string, posição 1 é número
const pair: [string, number] = ['idade', 30];

// Tupla do useState
const [count, setCount]: [number, (n: number) => void] = useState(0);

// Union
type Status = 'idle' | 'loading' | 'success' | 'error';
type StringOrNumber = string | number;

function format(value: StringOrNumber): string {
  if (typeof value === 'string') return value.toUpperCase(); // narrowing
  return value.toFixed(2);
}

// Intersection
type WithTimestamps = { createdAt: Date; updatedAt: Date };
type User = { id: number; name: string };
type UserWithTimestamps = User & WithTimestamps;

// Literal type
type Direction = 'north' | 'south' | 'east' | 'west';

function move(dir: Direction) { /* ... */ }
move('north'); // ✅
move('up');    // ❌ Erro

// as const: evita widening (string → 'north')
const DIRECTIONS = ['north', 'south', 'east', 'west'] as const;
type Direction2 = typeof DIRECTIONS[number]; // 'north' | 'south' | 'east' | 'west'

const CONFIG = { env: 'production', port: 8080 } as const;
// CONFIG.env é 'production', não string
